import React from 'react';

function Projects() {
  return (
    <section id="projects">
      <h2>My Projects</h2>
      <ul>
        <li>React Blog CMS</li>
        <li>Flask To-Do List</li>
        <li>AI Chatbot</li>
        <li>Face Recognition Attendance System</li>
      </ul>
    </section>
  );
}

export default Projects;
